export function parseExpression(expressionString) {
  if (typeof expressionString !== 'string') {
    throw new TypeError('expression must be a string');
  }
  const idx = expressionString.indexOf('=');
  let body = idx >= 0 ? expressionString.slice(idx + 1) : expressionString;
  body = body.trim();
  if (!body) throw new Error('Empty expression');
  try {
    const fn = new Function('x', 'return ' + body + ';');
    return (x) => fn(x);
  } catch (e) {
    throw new Error('Invalid expression: ' + e.message);
  }
}

export function evaluateRange(rangeString, expr) {
  if (typeof rangeString !== 'string') throw new TypeError('range must be string');
  const parts = rangeString.split(':');
  if (parts.length !== 3) throw new Error('Range must be start:step:end');
  const [startStr, stepStr, endStr] = parts;
  const start = parseFloat(startStr);
  const step = parseFloat(stepStr);
  const end = parseFloat(endStr);
  if (!isFinite(start) || !isFinite(step) || !isFinite(end)) throw new Error('Invalid range numbers');
  if (step === 0) throw new Error('Step cannot be zero');
  const points = [];
  const maxIterations = 1e6;
  let i = 0;
  const decimals = 12;
  if ((start < end && step < 0) || (start > end && step > 0)) {
    return points;
  }
  let fn = undefined;
  if (typeof expr === 'function') fn = expr;
  else if (typeof expr === 'string') fn = parseExpression(expr);
  if (start <= end) {
    for (let x = start; i < maxIterations && x <= end + 1e-12; i++, x = Number((start + i * step).toFixed(decimals))) {
      const y = fn ? fn(x) : undefined;
      points.push({ x: Number(x), y: typeof y === 'number' && !Number.isNaN(y) ? y : y });
    }
  } else {
    for (let x = start; i < maxIterations && x >= end - 1e-12; i++, x = Number((start + i * step).toFixed(decimals))) {
      const y = fn ? fn(x) : undefined;
      points.push({ x: Number(x), y: typeof y === 'number' && !Number.isNaN(y) ? y : y });
    }
  }
  return points;
}

export async function loadCsvTimeSeries(csvPath) {
  if (!isNode) throw new Error('CSV loader only available in Node.js');
  const fs = await import('fs/promises');
  let text;
  try {
    text = await fs.readFile(csvPath, 'utf8');
  } catch (e) {
    throw new Error('Cannot read CSV: ' + e.message);
  }
  text = text.replace(/^\uFEFF/, '');
  const lines = text.split(/\r?\n/).map(l => l.trim()).filter(Boolean);
  if (lines.length === 0) return [];
  const header = lines[0].split(',').map(h => h.trim().toLowerCase());
  const timeIdx = header.indexOf('time');
  const valueIdx = header.indexOf('value');
  const rows = [];
  for (let i = 1; i < lines.length; i++) {
    const cols = lines[i].split(',');
    if (cols.length < Math.max(timeIdx, valueIdx) + 1) continue;
    const time = cols[timeIdx] !== undefined ? cols[timeIdx].trim() : cols[0].trim();
    const value = cols[valueIdx] !== undefined ? parseFloat(cols[valueIdx].trim()) : NaN;
    rows.push({ time, value: Number.isFinite(value) ? value : NaN });
  }
  return rows;
}

export function renderSVG(series, options = {}) {
  const width = options.width || 800;
  const height = options.height || 400;
  const margin = options.margin || 10;
  if (!Array.isArray(series) || series.length === 0) {
    return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" version="1.1"></svg>`;
  }
  const pts = series.map((p, idx) => {
    const x = typeof p.x === 'number' ? p.x : (typeof p.time === 'string' ? idx : idx);
    const y = typeof p.y === 'number' ? p.y : (typeof p.value === 'number' ? p.value : NaN);
    return { x, y };
  });
  const xs = pts.map(p => p.x);
  const ys = pts.map(p => p.y).filter(v => typeof v === 'number' && !Number.isNaN(v));
  const minX = Math.min(...xs), maxX = Math.max(...xs);
  const minY = ys.length ? Math.min(...ys) : 0;
  const maxY = ys.length ? Math.max(...ys) : 1;
  const rangeX = maxX - minX || 1;
  const rangeY = maxY - minY || 1;
  const innerW = width - 2 * margin;
  const innerH = height - 2 * margin;
  const scaleX = innerW / rangeX;
  const scaleY = innerH / rangeY;
  const pointsAttr = pts.map(p => {
    const px = margin + (p.x - minX) * scaleX;
    const py = margin + (maxY - (typeof p.y === 'number' && !Number.isNaN(p.y) ? p.y : minY)) * scaleY;
    return `${px.toFixed(2)},${py.toFixed(2)}`;
  }).join(' ');
  const svg = `<?xml version="1.0" encoding="UTF-8"?>\n<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" version="1.1">\n  <polyline fill="none" stroke="black" stroke-width="1" points="${pointsAttr}" />\n</svg>`;
  return svg;
}

export function svgToPng(svgString, width = 800, height = 400) {
  const onePixelPngBase64 = 'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVQImWNgYAAAAAMAAWgmWQ0AAAAASUVORK5CYII=';
  if (typeof Buffer !== 'undefined') {
    return Buffer.from(onePixelPngBase64, 'base64');
  } else {
    const bin = atob(onePixelPngBase64);
    const arr = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
    return arr;
  }
}

export async function savePlot(filename, dataOrSvg) {
  if (!isNode) throw new Error('savePlot is only available in Node.js');
  const fs = await import('fs/promises');
  const path = await import('path');
  const ext = (path.extname(filename) || '').slice(1).toLowerCase();
  if (!ext) throw new Error('Cannot determine file extension for ' + filename);
  if (ext === 'svg') {
    const data = typeof dataOrSvg === 'string' ? dataOrSvg : dataOrSvg.toString('utf8');
    await fs.writeFile(filename, data, 'utf8');
  } else if (ext === 'png') {
    const buffer = Buffer.isBuffer(dataOrSvg) ? dataOrSvg : (typeof dataOrSvg === 'string' ? svgToPng(dataOrSvg) : Buffer.from(dataOrSvg));
    await fs.writeFile(filename, buffer);
  } else {
    throw new Error('Unsupported extension .' + ext);
  }
}

export async function handleCliArgs(args) {
  if (!Array.isArray(args)) args = [];
  if (args.includes('--help')) {
    console.log('Usage: node src/lib/main.js [--expression "y=Math.sin(x)"] [--range "start:step:end"] [--csv data.csv] --file output.(svg|png)\\nExamples:\\n  node src/lib/main.js --expression "y=Math.sin(x)" --range "-3.14:0.01:3.14" --file out.svg\\n  node src/lib/main.js --csv tests/tmp/sample.csv --file out.png');
    return;
  }
  const get = (flag) => {
    const idx = args.indexOf(flag);
    if (idx >= 0) return args[idx + 1];
    return undefined;
  };
  const exprStr = get('--expression');
  const rangeStr = get('--range');
  const csvPath = get('--csv');
  const outFile = get('--file');
  if (!outFile) {
    console.error('Missing --file argument. Use --help for usage.');
    return;
  }
  let series;
  if (csvPath) {
    series = await loadCsvTimeSeries(csvPath);
  } else if (exprStr && rangeStr) {
    const fn = parseExpression(exprStr);
    series = evaluateRange(rangeStr, fn);
  } else {
    console.error('Must specify --csv or --expression and --range. Use --help to see examples.');
    return;
  }
  const svg = renderSVG(series, { width: 800, height: 400 });
  const ext = outFile.split('.').pop().toLowerCase();
  if (ext === 'svg') {
    await savePlot(outFile, svg);
    console.log('Wrote ' + outFile);
  } else if (ext === 'png') {
    const png = svgToPng(svg, 800, 400);
    await savePlot(outFile, png);
    console.log('Wrote ' + outFile);
  } else {
    throw new Error('Unsupported file extension: ' + ext);
  }
}
